import streamlit as st
import torch
import re
import os
from transformers import AutoTokenizer, AutoModelForSequenceClassification

# Set up page configurations
st.set_page_config(
    page_title="Indic Language Sentiment Analysis", 
    page_icon="🌐",
    layout="centered"
)

MODEL_DIR = "models/indicbert"
LABEL_MAP = {0: "Negative", 1: "Positive"}
MAX_LENGTH = 64

# Load IndicBERT Model and Tokenizer
@st.cache_resource
def load_model():
    if not os.path.exists(MODEL_DIR):
        return None, None
    tokenizer = AutoTokenizer.from_pretrained(MODEL_DIR)
    model = AutoModelForSequenceClassification.from_pretrained(MODEL_DIR)
    model.eval()
    # Load on CPU for inference to save GPU memory for training/other processes
    device = torch.device("cpu")
    model.to(device)
    return tokenizer, model

tokenizer, model = load_model()

if model is None:
    st.error(
        f"❌ IndicBERT model not found at `{MODEL_DIR}/`.\n\n"
        "Please run `python src/train_indicbert.py` first to train and save the model."
    )
    st.stop()

device = next(model.parameters()).device

# Text Cleaning Function
def clean_text(text):
    # Keep punctuation and normalize whitespace as IndicBERT tokenizer handles punctuation
    text = re.sub(r'\s+', ' ', text).strip()
    return text

def predict_sentiment(text):
    inputs = tokenizer(
        text,
        return_tensors="pt",
        padding="max_length",
        truncation=True,
        max_length=MAX_LENGTH
    )
    inputs = {k: v.to(device) for k, v in inputs.items()}
    with torch.no_grad():
        outputs = model(**inputs)
    logits = outputs.logits
    probs = torch.softmax(logits, dim=-1)[0].cpu().tolist()
    pred_id = int(torch.argmax(logits, dim=-1).item())
    return LABEL_MAP[pred_id], probs

